            Summary = "A guided tour of the OEE dashboard: picking your dates, reading the shop-wide average OEE and world-class count, the per-work-center scores, and a closer look at one center's trend over time and its Six Big Losses.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/oee"]""",
            Tags = """["oee","manufacturing","metrics","walkthrough"]""",
            ContentJson = """{"appRoute":"/oee","startButtonLabel":"Tour OEE","steps":[{"element":"app-date-range-picker","popover":{"title":"Pick Your Dates","description":"Choose the stretch of time you want to measure — the last 30 days, this month, this week, or your own start and end dates. Everything on the page reflects the window you pick, so you can look at a rough week or a whole quarter.","side":"bottom"}},{"element":"app-kpi-chip","popover":{"title":"Average OEE & World-Class Count","description":"See the whole shop at a glance. One number is the average OEE across all work centers; the other counts how many centers hit the world-class mark. The color shifts from green to amber to red as the score drops.","side":"bottom"}},{"element":".oee-page__grid","popover":{"title":"Your Work Centers","description":"Each card is one work center. It shows the OEE score, the three factors — Availability, Performance, and Quality — and how many parts were made, good, and scrapped. A star marks a world-class center. Pick a card to see its details.","side":"top"}},{"element":"app-oee-work-center-card","popover":{"title":"A Single Work Center","description":"The big number up top is the OEE score for this center. It comes from multiplying the three factors, so it always sits below the weakest one. That tells you at a glance whether uptime, speed, or scrap is the thing to fix.","side":"top"}},{"element":".oee-page__detail","popover":{"title":"A Closer Look","description":"Pick a center and its details open here, under its name. You can trend the numbers by day, week, or month — day for a rough week, month to see whether a fix held over a season. This doesn't change the dates you're measuring.","side":"top"}},{"element":"app-oee-trend-chart","popover":{"title":"OEE Over Time","description":"This tracks Availability, Performance, Quality, and overall OEE over time for the center you picked. Use it to check whether a change actually helped, and to see which factor swings the most.","side":"top"}},{"element":"app-six-big-losses-chart","popover":{"title":"Six Big Losses","description":"This breaks lost minutes into six causes: breakdowns and setup (uptime), small stops and slow running (speed), and scrap during steady running and during startup (quality). The biggest one is where to focus first.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "OEE Field Reference",
            Slug = "oee-field-reference",
            Summary = "Complete reference for the OEE factors and formula, every metric behind a work-center's score, the Six Big Losses, world-class benchmarks, and how to read the numbers and act on them.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/oee"]""",
            Tags = """["oee","manufacturing","metrics","reference"]""",
            ContentJson = """{"title":"OEE Field Reference","groups":[{"heading":"The OEE Formula","items":[{"label":"OEE","value":"Availability times Performance times Quality, shown as a percentage. Because the three multiply, OEE always lands below the weakest one."},{"label":"Availability","value":"Run time divided by the time you planned to run. Did the machine run when it was scheduled to? Breakdowns, unplanned stops, and long setups pull it down."},{"label":"Performance","value":"How fast it ran versus the ideal speed while it was running. Small stops, idling, and slow running pull it down. It should never top 100%."},{"label":"Quality","value":"Good parts divided by all parts made. How many came out right the first time? Scrap and rework pull it down."}]},{"heading":"Time Metrics (per work center)","items":[{"label":"Scheduled Minutes","value":"How many minutes the work center was set to run during the stretch you're looking at."},{"label":"Planned Downtime Minutes","value":"Planned stops like breaks and scheduled maintenance. Taken out of scheduled time to get available time."},{"label":"Unplanned Downtime Minutes","value":"Unexpected stops like breakdowns and failures. These lower Availability."},{"label":"Available Minutes","value":"Scheduled minutes minus planned downtime. This is the time the machine was expected to run."},{"label":"Run Time Minutes","value":"How many minutes the machine actually ran."},{"label":"Ideal Cycle Time (seconds)","value":"The fastest possible time to make one part. Used to measure Performance — if you set it too fast, Performance climbs past 100% and you know the number is off."}]},{"heading":"Production Counts (per work center)","items":[{"label":"Total Quantity","value":"Every part made in the stretch you're looking at — good, scrap, and rework combined."},{"label":"Good Quantity","value":"Parts that came out right the first time."},{"label":"Scrap Quantity","value":"Parts thrown out as defective. These lower Quality."},{"label":"Rework Quantity","value":"Parts that had to be fixed. These count against first-time Quality."}]},{"heading":"The Six Big Losses","items":[{"label":"Equipment Failure (uptime)","value":"Minutes lost to breakdowns and unexpected stops."},{"label":"Setup & Adjustment (uptime)","value":"Minutes lost to changeovers, tool changes, and warm-up."},{"label":"Idling & Minor Stops (speed)","value":"Minutes lost to short stops and jams, or when the machine is blocked or waiting on material."},{"label":"Reduced Speed (speed)","value":"Minutes lost to running slower than the ideal speed."},{"label":"Process Defects (quality)","value":"Minutes lost to scrap and defects while the machine runs steadily."},{"label":"Reduced Yield (quality)","value":"Minutes lost to defects during startup, warm-up, or right after a changeover."},{"label":"Total Loss Minutes","value":"All six causes added together — your total lost minutes for the period."}]},{"heading":"World-Class Benchmark","items":[{"label":"World-Class OEE","value":"About 85% OEE overall — roughly 90% Availability, 95% Performance, and 99% Quality. Hit it and the center earns a star."},{"label":"Average OEE color","value":"The average score reads green at 85% and up, amber from 60% to 84%, and red below 60% — a quick health color for the shop."},{"label":"World-Class Count","value":"How many work centers are world-class out of the total. Watch it climb as you improve the floor."}]},{"heading":"Reading the Numbers","items":[{"label":"Start with the weakest factor","value":"OEE always sits below your lowest factor. Find that factor first — it's the one holding the center back, and fixing it moves the score the most."},{"label":"Low Availability","value":"The machine isn't running when it should. Chase breakdowns and long changeovers — the Equipment Failure and Setup losses."},{"label":"Low Performance","value":"It runs, but slow. Chase small stops, jams, and reduced speed. Also sanity-check the ideal cycle time isn't set wrong."},{"label":"Low Quality","value":"It runs fast but makes bad parts. Chase scrap and rework — the Process Defects and Reduced Yield losses."},{"label":"Trend it over time","value":"Look at the score day by day for a rough week, or month by month to see whether a fix held over a season. A change that helped shows up as a step in the line."},{"label":"Read the loss breakdown","value":"The tallest of the six loss bars is where your minutes are going. Aim your next improvement there, not at the factor that's already fine."},{"label":"No data yet","value":"A work center only shows up once there's production to score for the dates you're looking at. A blank stretch means no jobs ran there, not a broken number."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "OEE Knowledge Check",
            Slug = "oee-quiz",
            Summary = "Test your knowledge of OEE: the three factors and formula, world-class benchmarks, the Six Big Losses, the metrics behind each factor, and the dashboard.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/oee"]""",
            Tags = """["oee","manufacturing","metrics","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"oe1","text":"What is the OEE formula?","options":[{"id":"a","text":"Availability + Performance + Quality"},{"id":"b","text":"Availability x Performance x Quality","isCorrect":true},{"id":"c","text":"(Availability + Performance + Quality) / 3"},{"id":"d","text":"Run Time / Scheduled Time"}],"explanation":"OEE is the product of the three factors: Availability x Performance x Quality. Because they multiply, OEE is always lower than the weakest factor — losses compound rather than average out."},{"id":"oe2","text":"A work center is 90% Availability, 90% Performance, and 90% Quality. What is its OEE?","options":[{"id":"a","text":"90%"},{"id":"b","text":"about 73%","isCorrect":true},{"id":"c","text":"270%"},{"id":"d","text":"about 95%"}],"explanation":"0.90 x 0.90 x 0.90 = 0.729, or about 73%. This is the key insight of OEE: three 'good-looking' factors still multiply down to a mediocre overall score."},{"id":"oe3","text":"Which factor does an unplanned machine breakdown hurt?","options":[{"id":"a","text":"Quality"},{"id":"b","text":"Performance"},{"id":"c","text":"Availability","isCorrect":true},{"id":"d","text":"None — breakdowns are excluded from OEE"}],"explanation":"Availability is run time divided by available time. A breakdown stops the machine when it should be running, so it directly reduces Availability. (It maps to the Equipment Failure loss category.)"},{"id":"oe4","text":"How is Quality calculated?","options":[{"id":"a","text":"Run Time / Scheduled Time"},{"id":"b","text":"Good Quantity / Total Quantity","isCorrect":true},{"id":"c","text":"Ideal Cycle Time x Total Quantity"},{"id":"d","text":"Scrap Quantity / Good Quantity"}],"explanation":"Quality is good parts divided by total parts produced. Both scrap and rework reduce it — a part that needs rework was not made right the first time, so it counts against first-time quality."},{"id":"oe5","text":"A work center is flagged 'world-class.' What benchmark does that correspond to?","options":[{"id":"a","text":"100% OEE"},{"id":"b","text":"Roughly 85% OEE (about 90% Availability, 95% Performance, 99% Quality)","isCorrect":true},{"id":"c","text":"Exactly 60% OEE"},{"id":"d","text":"Any OEE above 50%"}],"explanation":"The recognized world-class benchmark is about 85% OEE, which breaks down to roughly 90% Availability, 95% Performance, and 99% Quality. Work centers at or above it are marked world-class with a star badge, and the dashboard counts them."},{"id":"oe6","text":"Reduced Speed (running slower than the ideal cycle time) belongs to which of the Six Big Losses groupings?","options":[{"id":"a","text":"An Availability loss"},{"id":"b","text":"A Performance loss","isCorrect":true},{"id":"c","text":"A Quality loss"},{"id":"d","text":"It is not one of the Six Big Losses"}],"explanation":"Reduced Speed is a Performance loss, alongside Idling & Minor Stops. Availability losses are Equipment Failure and Setup & Adjustment; Quality losses are Process Defects and Reduced Yield."},{"id":"oe7","text":"Which two losses are the Quality-related Six Big Losses?","options":[{"id":"a","text":"Equipment Failure and Setup & Adjustment"},{"id":"b","text":"Idling & Minor Stops and Reduced Speed"},{"id":"c","text":"Process Defects and Reduced Yield","isCorrect":true},{"id":"d","text":"Equipment Failure and Reduced Speed"}],"explanation":"Process Defects (scrap during steady-state running) and Reduced Yield (defects during startup/warm-up or after a changeover) are the two Quality losses. Together with the Availability and Performance pairs, they make up the Six Big Losses that sum to total lost minutes."},{"id":"oe8","text":"What does Available Minutes equal?","options":[{"id":"a","text":"Scheduled Minutes plus planned downtime"},{"id":"b","text":"Scheduled Minutes minus planned downtime","isCorrect":true},{"id":"c","text":"Run Time minus scrap time"},{"id":"d","text":"Total Quantity x Ideal Cycle Time"}],"explanation":"Available time is the scheduled time minus planned downtime (breaks, planned maintenance). It is the denominator for Availability — run time divided by available minutes."},{"id":"oe9","text":"You want to know whether a change you made to a machine actually helped its OEE. What's the best way to check?","options":[{"id":"a","text":"Look at the list of customers for that work center"},{"id":"b","text":"Trend the center's OEE over time and look for a step up after the change","isCorrect":true},{"id":"c","text":"Type a new, higher OEE score in by hand"},{"id":"d","text":"Nothing — OEE can't show change over time"}],"explanation":"OEE is trended over time, so a real improvement shows up as a step up in the line after you made the change. You can also see which factor moved. You never type a score in by hand — you move it by improving the floor, and the number follows."},{"id":"oe10","text":"You improved a center's Availability from 80% to 90%, but its OEE barely moved. What's the most likely reason?","options":[{"id":"a","text":"Another factor — Performance or Quality — is still low and is now the thing holding OEE back","isCorrect":true},{"id":"b","text":"Availability doesn't actually affect OEE"},{"id":"c","text":"OEE can never change once it's set"},{"id":"d","text":"Raising Availability always lowers OEE"}],"explanation":"OEE is the three factors multiplied, so it only climbs as much as your weakest factor lets it. If OEE barely moved after an Availability gain, the bottleneck shifted — Performance or Quality is now the weak factor. Check the loss breakdown and aim your next fix there."},{"id":"oe11","text":"Why can Performance never legitimately exceed 100%?","options":[{"id":"a","text":"Because it is capped at 100% no matter how the machine runs"},{"id":"b","text":"Because nothing can run faster than the ideal cycle time, which is defined as the theoretical fastest — if Performance exceeds 100%, the ideal cycle time is set too slow","isCorrect":true},{"id":"c","text":"Because Performance is the same as Quality"},{"id":"d","text":"It can — Performance above 100% is normal"}],"explanation":"Performance compares ideal-cycle-time-times-quantity against actual run time. The ideal cycle time is the theoretical fastest achievable, so a value over 100% means the ideal was set too slow, not that the machine beat physics — it's a data-quality signal."},{"id":"oe12","text":"A work center has high Availability and high Performance but low OEE. Where is the problem?","options":[{"id":"a","text":"Quality — scrap and rework are dragging the score down","isCorrect":true},{"id":"b","text":"Availability — the machine isn't running"},{"id":"c","text":"Performance — the machine is running slow"},{"id":"d","text":"There is no problem; OEE is unrelated to the factors"}],"explanation":"Since OEE is the product of the three factors, if Availability and Performance are both high but OEE is low, Quality must be the weak factor — meaning scrap and rework. The Six Big Losses Quality categories (Process Defects, Reduced Yield) would show where."}]}"""
        });

        Log.Information("Seeded OEE training modules");
    }
}
